-- =============================================================
-- Cap nhat PRODUCTION: So tay nuoc di tu hoc cua AI (choi voi may)
-- Tao bang ai_book + nap san 340 the khai cuoc.
-- Cach chay: phpMyAdmin -> chon database -> tab SQL -> dan file nay -> Go.
-- (Hoac: mysql -u USER -p DBNAME < ai_book.sql)
-- An toan chay lai nhieu lan (IF NOT EXISTS + INSERT IGNORE).
-- =============================================================

CREATE TABLE IF NOT EXISTS ai_book (
  pos_hash   CHAR(32)    NOT NULL,
  move       VARCHAR(12) NOT NULL,
  plays      INT         NOT NULL DEFAULT 0,
  wins       INT         NOT NULL DEFAULT 0,
  losses     INT         NOT NULL DEFAULT 0,
  updated_at DATETIME    NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (pos_hash, move),
  INDEX idx_pos (pos_hash)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;





